// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Voting_Struct{
    address owner;

    event add_party(uint id,string name,uint voteCount);
    event add_voter(uint id,string name,bool isVoted,address wallet);
    event _vote(uint partyId,address wallet);
    event party_votes(uint partyId,uint votes);

    constructor(){
        owner=msg.sender;
    }
    modifier checkOwner{
        require(owner==msg.sender,"Access Denied");
        _;
    }
    
    //parties
    struct Party{
        uint id;
        string name;
        uint voteCount;
    }
    mapping (uint => Party) parties;
    mapping (uint => bool) isPartyExist;
    uint[] allPartyIds;

    function addParty(uint id, string memory name) public checkOwner{
        require(!isPartyExist[id],"Party already existed");
        allPartyIds.push(id);
        isPartyExist[id]=true;
        parties[id] = Party(id,name,0);

        emit add_party(id, name, 0);
    }

    //Voters
     struct Voter{
        uint id;
        string name;
        bool isVoted;
        address wallet;
    }    
    mapping (uint => Voter) Voters;
    mapping (uint => bool) isVoterExisted;
    mapping (address => bool) hasRegistered;
    mapping (address => bool) hasVoted;
    uint[] allVoters;

    function addVoter(uint id, string memory name) public{
        require(!isVoterExisted[id],"Voter already existed");
        require(!hasRegistered[msg.sender], "Voter already existed");
        allVoters.push(id);
        isVoterExisted[id]=true;
        hasRegistered[msg.sender]=true;
        Voters[id] = Voter(id,name,false,msg.sender);

        emit add_voter(id, name, false, msg.sender);
    }

    //Voting
    function vote(uint partyId) public {
        require(hasRegistered[msg.sender], "Not registered as voter");
        require(!hasVoted[msg.sender], "Already voted");
        require(isPartyExist[partyId], "Invalid party");

        parties[partyId].voteCount++;
        hasVoted[msg.sender] = true;

        emit _vote(partyId, msg.sender);
    }

    //getVotingDetails
     function getPartyVotes(uint partyId) public returns (string memory, uint){
        require(isPartyExist[partyId], "Party not found");

        Party memory p = parties[partyId];
        emit party_votes(partyId, p.voteCount);
        return (p.name, p.voteCount);
    }

}

Practice/ProductInventory.sol.content:
// 5. Product Inventory System

// Requirements:

// Array of product IDs
// Mapping for product stock (productId => quantity)
// Function to add product:
// Use require to ensure product doesn't already exist
// Function to buy product:
// Use require to check stock availability

// Expected Output:

// No duplicate product IDs
// Stock reduces after purchase
// Cannot buy out-of-stock product

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Product_Inventory{
    uint[] productID;
    mapping (uint => uint) product_stock;
    mapping (uint => bool) isExisted;

    function addProductID(uint id,uint quantity) public{
        require(!isExisted[id],"Id already exist");
       
        productID.push(id);
        product_stock[id]=quantity;
        isExisted[id]=true;
    }

    function buyProduct(uint id, uint quantity) public{
        require(isExisted[id],"Invalid Id");
        require(product_stock[id]>=quantity,"Invalid quantity");
     
        product_stock[id]-=quantity;
    }

     function getFullDetails() public view returns (uint[] memory, uint[] memory) {
        uint[] memory all_products=new uint[](productID.length);
        for (uint i = 0; i < productID.length; i++) {
            all_products[i]= product_stock[productID[i]];
        }

        return (productID, all_products);
    }
}

